defmodule BlogWeb.PostLive.FormComponent do
  use Phoenix.LiveView

  defp render_content(post) when post !== nil, do: raw(post.content)

  def mount(_, _, socket) do
    {:ok, assign(socket, :post, %Post{})}
  end

  def handle_info({:update_post, post}, socket) do
    {:noreply, assign(socket, :post, post)}
  end

  def render(assigns) do
    ~L"""
    <div>
      <%= for field <- @post.__fields__() do %>
        <%= if field.actionable? do %>
          <%= label(field.name) %>:
          <%= if field.type == "text" || field.type == "textarea" do %>
            <%= text_input(field.name, value: @post[field.name], placeholder: "#{field.human_name()}" ) %>
          <% else %>
            <%= select(field.name, options_for_select(@options), value: @post[field.name]) %>
          <% end %>
        <% end %>
      <% end %>

      <%= label("Content") %>:
      <%= textarea(:content) %>

      <button phx-click="save">Save</button>
    </div>
    """
  end
end

defmodule BlogWeb.PostLive do
  use Phoenix.LiveView, layout: {BlogWeb.LayoutView, "live.html"}

  def render(assigns) do
    ~L"""
    <div>
      <%= render @post %>
    </div>
    """
  end
end

defmodule BlogWeb.Router do
  def route(%{path_info: "/posts"}, _conn, assigns) do
    {:ok,
     assign(
       assigns,
       post: Blog.Repo.get(Post, assigns[:id])
     )}
  end
end